custom_scripts.script:
frappe.ui.form.on('Lead', {
	refresh: function(frm) {
        setTimeout(() => {
            frm.remove_custom_button('Opportunity', 'Create'); 
        }, 10);

        if (!frm.is_new() && frm.doc.__onload && !frm.doc.__onload.is_customer) {
            setTimeout(() => {
                frm.add_custom_button(
                    __("Opportunity"),
                    function () {
                        frm.trigger("custom_make_opportunity");
                    },
                    __("Create")
                );
            }, 50);
        }
    },

    custom_make_opportunity: async function (frm) {
        if (!frm.doc.company_name) {
            frm.set_value("company_name", frm.doc.lead_name || frm.doc.first_name || frm.doc.last_name || "Default Company");
            await frm.save();  
        }

        frappe.model.open_mapped_doc({
            method: "erpnext.crm.doctype.lead.lead.make_opportunity",
            frm: frm,
        });
    }
})

frappe.ui.form.on('Lead', {
    custom_customer_category: function(frm) {
        if (frm.doc.custom_customer_category) {
            frm.set_query("custom_customer_subcategory", function() {
                return {
                    filters: {
                        parent_customer_group: frm.doc.custom_customer_category
                    }
                };
            });
        } else {
            frm.set_query("custom_customer_subcategory", function() {
                return {};
            });
        }
    }
});

frappe.ui.form.on('Lead', {
    custom_state_name: function(frm) {
        if (frm.doc.custom_state_name) {
            frappe.call({
                method: 'frappe.client.get_value',
                args: {
                    doctype: 'Territory',
                    filters: { name: frm.doc.custom_state_name },
                    fieldname: 'parent_territory'
                },
                callback: function(r) {
                    if (r.message) {
                        frm.set_value('territory', r.message.parent_territory);
                    }
                }
            });
        }
    }
});

frappe.ui.form.on('Lead', {
    lead_owner: function(frm) {
        frm.set_value('custom_state_name', ''); 
        frm.refresh_field('custom_state_name');

        if (frm.doc.lead_owner) {
            frappe.call({
                method: "frappe.client.get_list",
                args: {
                    doctype: "User Permission",
                    filters: {
                        user: frm.doc.lead_owner,
                        allow: "Territory"
                    },
                    fields: ["for_value"]
                },
                callback: function(response) {
                    if (response.message && response.message.length > 0) {
                        let parent_territory = response.message[0].for_value;

                        frappe.call({
                            method: "frappe.client.get_list",
                            args: {
                                doctype: "Territory",
                                filters: {
                                    parent_territory: parent_territory
                                },
                                fields: ["territory_name"]
                            },
                            callback: function(res) {
                                if (res.message) {
                                    let allowed_states = res.message.map(t => t.territory_name);

                                    let all_states = [
                                        "Andaman and Nicobar Islands", "Andhra Pradesh", "Arunachal Pradesh", "Assam",
                                        "Bihar", "Chandigarh", "Chhattisgarh", "Dadra and Nagar Haveli and Daman and Diu",
                                        "Delhi", "Goa", "Gujarat", "Haryana", "Himachal Pradesh", "Jammu and Kashmir",
                                        "Jharkhand", "Karnataka", "Kerala", "Ladakh", "Lakshadweep Islands",
                                        "Madhya Pradesh", "Maharashtra", "Manipur", "Meghalaya", "Mizoram",
                                        "Nagaland", "Odisha", "Puducherry", "Punjab", "Rajasthan", "Sikkim",
                                        "Tamil Nadu", "Telangana", "Tripura", "Uttar Pradesh", "Uttarakhand",
                                        "West Bengal"
                                    ];

                                    let filtered_states = all_states.filter(state => allowed_states.includes(state));

                                    frm.set_df_property('custom_state_name', 'options', [''].concat(filtered_states));
                                    frm.refresh_field('custom_state_name');
                                }
                            }
                        });
                    } else {
                        frm.set_df_property('custom_state_name', 'options', ['']);
                        frm.refresh_field('custom_state_name');
                    }
                }
            });
        } else {
            frm.set_df_property('custom_state_name', 'options', ['']);
            frm.refresh_field('custom_state_name');
        }
    }
});
